SELECT COUNT(DISTINCT LPB.PK) AS QUANTIDADE FROM LATTES_P_PRODBIB LPP JOIN LATTES_PRODBIB LPB ON LPP.FK_PRODBIB = LPB.PK JOIN SERVIDOR S ON S.PK_SIAPE = LPP.FK_SIAPE WHERE LOWER(LPB.TIPO) LIKE LOWER('%capitulo de livro%') AND TRIM(LOWER(COALESCE(LPB.ANO, ''))) = '2023' AND LOWER(S.SIGLA_CAMPUS) = LOWER('oes') AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%educa%'